use std::sync::{Arc, Barrier};
use std::thread;

fn main() {
    const NUM_WORKERS: usize = 5;
    let barrier = Arc::new(Barrier::new(NUM_WORKERS + 1));
    let mut handles = vec![];

    for i in 0..NUM_WORKERS {
        let b_clone = Arc::clone(&barrier);
        let handle = thread::spawn(move || {
            println!("Worker {} starting its task.", i); 
            thread::sleep(std::time::Duration::from_millis((i as u64) * 100));
            println!("Worker {} finished task, waiting at barrier.", i);
            b_clone.wait();
            println!("Worker {} passed the barrier and continuing execution.", i);
        });
        handles.push(handle);
    }

    let main_guard = Arc::clone(&barrier);
    let main_handle = thread::spawn(move || {
        thread::sleep(std::time::Duration::from_millis(200)); 
        println!("Main thread waiting to start all workers.");
        main_guard.wait();
        println!("All workers have arrived; main process continuing.");
    });
    handles.push(main_handle);

    for handle in handles {
        handle.join().unwrap();
    }
}

