use std::sync::{Arc, Barrier};
use std::thread;

struct RecordProcessor {
    id: usize,
}
impl RecordProcessor {
    fn new(id: usize) -> Self {
        RecordProcessor { id }
    }
    fn process_batch(&self, barrier: Arc<Barrier>) -> i32 {
        println!("Worker {} started processing.", self.id);
        let sleep_duration = ((self.id % 3 + 1) * 50) as u64;
        let result = thread::sleep(std::time::Duration::from_millis(sleep_duration));
        barrier.wait();
        println!("Worker {} finished processing after waiting.", self.id);
        self.id as i32
    }
}

fn main() {
    const NUM_WORKERS: usize = 5;
    let barrier = Arc::new(Barrier::new(NUM_WORKERS));
    let mut handles = vec![];

    for i in 0..NUM_WORKERS {
        let processor = RecordProcessor::new(i);
        let barrier_clone = Arc::clone(&barrier);
        let handle = thread::spawn(move || {
            processor.process_batch(barrier_clone)
        });
        handles.push(handle);
    }

    let mut results = vec![];
    for handle in handles {
        results.push(handle.join().unwrap());
    }

    println!("nAll processing complete. Results: {:?}", results);
